#include <bits/stdc++.h>
using namespace std;
long long n,prime[10005],ans,cnt,f[1005][1005];
bool vis[10005];
void xxs(int n){
	for(int i=2;i<=10005;i++){
		if(!vis[i]) prime[++cnt]=i;
		for(int j=1;j<=cnt&&i*prime[j]<=10005;j++){
      		vis[i*prime[j]]=1;
      		if(i%prime[j]==0) break;
    	}
	}
}
long long dfs(int a,int b){
    if(a==0)return 1;
    if(f[a][b] != -1) return f[a][b];
    f[a][b] = 0; 
    if(a<0) return 0;
    else{
        for(int i=0;prime[i]<=a&&prime[i]<=b;i++){
            f[a][b] +=dfs(a-prime[i],prime[i]);
        }return f[a][b];
    }

}
int main(){
    memset(f, -1, sizeof f);
    cin>>n;
    xxs(n);
    cout<<dfs(n,n);
    return 0;
}
